var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"새디어스 모건은 왼쪽 눈을 잃었다.","JPN":"タデウス・モーガンは左目を失った。","ENG":"Thaddeus Morgan lost his left eye.","TWN":"薩迪烏斯·摩根失去了左眼。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"咳……！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"왜 그러지? 큰소리 칠 땐 언제고, 일반 탄환에도 쩔쩔매나?","JPN":"おいおい、あの威勢の良さはどうした。こんな一般の弾丸にも対応できないのか？","ENG":"What's the matter? What happened to all that tough talk? Now you're struggling with normal bullets.","TWN":"怎麼？剛剛還大言不慚，現在被普通子彈打得手足無措啊？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네의 각오가 겨우 이 정도 밖에 안 되었다면, 이거 실망이야.","JPN":"君の覚悟がこの程度などだとしたら、がっかりだな。","ENG":"I'm disappointed if your determination is only this much.","TWN":"如果你的覺悟才這麼點，那未免太讓人失望了。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이래서야 학회 녀석들이 살짝 겁만 줘도, 기관의 화장실 개수까지 술술 불겠군!","JPN":"これでは学会のやつらが少し脅しただけで、機関のトイレの数まで白状しそうだ！","ENG":"At this rate, I'm sure that if the Society blokes give you a tiny scare, you'll be singing like a canary about all the Institution's secrets!","TWN":"你這副樣子如果讓學會的傢伙稍微嚇唬一下，恐怕連機關有幾間廁所都會說出來！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"시끄러워, 이 망할 할배!","JPN":"うるさい、このクソジジイ！","ENG":"Shut it, you!","TWN":"吵死了，臭老頭！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"카운터라고 해도, 무리하면 부상을 입는 건 똑같다.","JPN":"いくらカウンターでも、無理をすれば怪我するのはみんな同じだ。","ENG":"Even Counters get hurt like everyone else if they strain themselves.","TWN":"就算是制裁者，勉強行事也會受傷。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"수차례 수술을 거친 회전근개는 이제 거의 한계에 다다라서.","JPN":"何度も手術を受けたあの肩は、もう限界に近い。","ENG":"After countless surgeries to the rotator cuff, it has almost reached its limit.","TWN":"經過數次手術的肩膀現在已經快到極限了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"모건 할배는 주머니 속 오른쪽 손을 어깨 위로 올리지 못한다.","JPN":"モーガンのジジイはポケットの中にある右手を、肩から上には上げられない。","ENG":"And that's why Morgan can't raise his right hand above his shoulder.","TWN":"摩根老頭沒法把口袋裡的右手抬上肩膀。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"몇 번이나 말하지 않았나, 애송이! 공격이 너무 단조롭다고!","JPN":"何度も言わせるな、小僧！　攻撃が普通すぎる！","ENG":"How many times do I have to repeat myself, kid? Your attacks are tactless!","TWN":"我說過很多次，小鬼！你的攻擊太單調了！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아무리 재빠르게 휘둘러봐야 그런 일직선 공격은 에어로빅하는 할머니도 피하겠어!","JPN":"いくら早く振り回しても、そんな一直線の攻撃では体操しているお婆さんにも避けられてしまうぞ！","ENG":"What good is speed when a granny doing aerobics can avoid those straightforward attacks?!","TWN":"不管怎麼快速地揮動，那種直線攻擊就連跳健美操的老奶奶都能避開吧！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"형님께서 넘긴 봉인 사슬은 줄넘기 할 때 쓰려고 하나?","JPN":"バーネットからもらったその封印の鎖は縄跳び用か？","ENG":"Do you use that Sealing Chain your grandfather left you to jump rope?","TWN":"大哥給你的封印鎖鏈是留著用來跳繩的嗎？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"커흑!","JPN":"がはっ！","ENG":"Gaaagh!","TWN":"咳！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"늙은이의 주먹질 맛은 어떤가? 아직 쓸만하지?","JPN":"どうだ、老人のげんこつは？　まだ十分使えるだろう？","ENG":"How does an old man's punch taste like, huh? I still got it, no?","TWN":"我這個老頭的拳頭感覺怎麼樣？是不是還堪用？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"더럽게…… 아프다고, 젠장……!","JPN":"くそ……痛ってぇな、ちくしょう……！","ENG":"It... bloody... hurts...! Dammit...!","TWN":"真的……很痛欸，該死……！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 엄살 부리긴! 자네나 나나 카운터로서의 자질은 거기서 거기야.","JPN":"はは、情けない！　君も俺も、カウンターとしての素質は五分五分だ。","ENG":"Hah hah, stop being a crybaby! You and I are not that different when it comes to our qualities as a Counter.","TWN":"哈哈，別裝了！無論是你，還是我，身為制裁者的資質都差不多。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 항상 말했듯, 싸움이라는 게 그저 CRF 출력만으로 결정되는 건 아니거든.","JPN":"だがいつも言っているように、戦いというのはCRF出力の強さだけで決着がつくものではない。","ENG":"But as I've said to you time and time again, fights are not determined merely by one's CRF output.","TWN":"但是，正如我常說的，戰鬥並不是只由CRF的輸出決定的。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"원페어를 들고서도, 포카드에게 죽지 않을 배짱을 기르도록 해!","JPN":"ワンペアを手にしていても、フォーカードに負けない度胸を育てろ！","ENG":"You need to learn to have the guts to not fold against a four of a kind even when you only have a pair!","TWN":"要拿就算手中只有一對，也不會葫蘆牽制的氣魄！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나도 알고 있다고!","JPN":"わかってるよ！","ENG":"You don't have to remind me!","TWN":"我也知道！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"간다, 할배!","JPN":"行くぞ、ジジイ！","ENG":"Try to block this, old chap!","TWN":"接招吧，老頭！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"그로니아에서 그림자에게 찔린 부상은 결국 침식증후군으로 이어졌다.","JPN":"グロニアでシャドウに刺されたところは、結局侵食症候群に繋がった。","ENG":"The wound he sustained from the Shadow in Gronia developed into Corruption Syndrome.","TWN":"在格羅尼亞被暗影刺傷的傷口最終病變成侵蝕症候群。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"초기라고 해도 침식증후군은 불치병이다.","JPN":"初期だとしても、侵食症候群は不治の病だ。","ENG":"Although it's in its early stages, Corruption Syndrome is incurable.","TWN":"即使是初期，侵蝕症候群也是不治之症。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"아마도 모건 할배의 말로는 결코 평온하지 못하겠지.","JPN":"たぶん、モーガンのジジイの末路は決して穏やかではないだろう。","ENG":"And because of this, Morgan's remaining days won't be a pleasant one.","TWN":"也許摩根老頭的結局並不會平靜。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"그럼에도…….","JPN":"それでも……","ENG":"And yet...","TWN":"盡管如此……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};